/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataFieldEventHandler(formDataFieldStr(MarkupTable, MarkupTable, ETGStdPosting), FormDataFieldEventType::Validating)]
public static void ETGStdPosting_OnValidating(FormDataObject sender, FormDataFieldEventArgs e)
{
    FormDataSource MarkupTable_ds               = sender.datasource();
    MarkupTable    markupTableLOc  = MarkupTable_ds.cursor();

    if(markupTableLOc.ETGContractPosting == NoYes::Yes)
    {
        throw error('@ETG_New:ETGContractAssign');
    }
}

